const svg = $('#adele-svg'), out = $('#adele-out');
const primes = [2,3,5,7,11,13];
const W=620, H=320;
const centerX=310, centerY=160;
const ringR=120;
let selected = null;

const descriptions = {
  'inf': 'Archimedean place v_∞: completion is ℝ. Open sets are the usual open intervals.',
  2:   'p=2 (dyadic): ℚ₂ with 2-adic metric. The compact open subring ℤ₂ = {..., -2,-1,0,1,2,...} (2-adically). A number like 1/3 is in ℤ₂ since |1/3|₂ = 1.',
  3:   'p=3: ℚ₃ with 3-adic metric. ℤ₃ = {x : |x|₃ ≤ 1}. The series 1+3+9+27+⋯ = -1/2 converges 3-adically!',
  5:   'p=5: ℚ₅. Note that √(-1) exists in ℚ₅ (since -1 ≡ 4 = 2² mod 5, and Hensel lifting works).',
  7:   'p=7: ℚ₇. ℤ₇ is open and compact; every element has a unique 7-adic expansion Σaₙ·7ⁿ, aₙ ∈ {0,...,6}.',
  11:  'p=11: ℚ₁₁. The residue field is ℤ/11ℤ = 𝔽₁₁.',
  13:  'p=13: ℚ₁₃. For all p shown, the adèle ring stipulates: the component at p must lie in ℤₚ for all but finitely many p.',
};

function draw(sel){
  svg.innerHTML = '';

  // central node: A_Q
  svg.appendChild(SVG('circle',{cx:centerX,cy:centerY,r:38,fill:'var(--panel2)',stroke:'var(--yellow)','stroke-width':2}));
  const ct = SVG('text',{x:centerX,y:centerY-6,'text-anchor':'middle','font-size':14,fill:'var(--yellow)','font-weight':'bold'});
  ct.textContent = 'A_Q'; svg.appendChild(ct);
  const ct2 = SVG('text',{x:centerX,y:centerY+12,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
  ct2.textContent = 'adèle ring'; svg.appendChild(ct2);

  // archimedean node
  const ax = centerX, ay = centerY - ringR - 20;
  const archimedeanSel = sel === 'inf';
  const acol = archimedeanSel ? 'var(--cyan)' : 'var(--blue)';
  svg.appendChild(SVG('line',{x1:centerX,y1:centerY-38,x2:ax,y2:ay+22,stroke:'var(--line)','stroke-width':1.5}));
  svg.appendChild(SVG('ellipse',{cx:ax,cy:ay,rx:42,ry:22,fill:archimedeanSel?'rgba(125,224,214,0.15)':'var(--panel2)',stroke:acol,'stroke-width':1.8}));
  const at = SVG('text',{x:ax,y:ay-4,'text-anchor':'middle','font-size':13,fill:acol,'font-weight':'bold'});
  at.textContent = 'ℝ'; svg.appendChild(at);
  const at2 = SVG('text',{x:ax,y:ay+11,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
  at2.textContent = 'v_∞'; svg.appendChild(at2);

  // clickable overlay for archimedean
  const aHit = SVG('ellipse',{cx:ax,cy:ay,rx:42,ry:22,fill:'transparent',style:'cursor:pointer'});
  aHit.addEventListener('click',()=>{ selected = selected==='inf'?null:'inf'; draw(selected); out.textContent = selected ? descriptions['inf'] : 'Click a node to see details.'; });
  svg.appendChild(aHit);

  // prime nodes arranged in a semicircle at bottom
  primes.forEach((p,i)=>{
    const angle = Math.PI * (0.1 + 0.8*i/(primes.length-1));
    const px = centerX + (ringR+10)*Math.cos(Math.PI + angle);
    const py = centerY + (ringR-10)*Math.sin(angle);
    const isSel = sel===p;
    const col = isSel ? 'var(--pink)' : 'var(--violet)';

    svg.appendChild(SVG('line',{x1:centerX,y1:centerY+38,x2:px,y2:py-18,stroke:'var(--line)','stroke-width':1}));

    svg.appendChild(SVG('ellipse',{cx:px,cy:py,rx:34,ry:19,fill:isSel?'rgba(224,122,95,0.15)':'var(--panel2)',stroke:col,'stroke-width':1.8}));
    const pt = SVG('text',{x:px,y:py-3,'text-anchor':'middle','font-size':13,fill:col,'font-weight':'bold'});
    pt.textContent = `ℚ${p}`; svg.appendChild(pt);
    const pt2 = SVG('text',{x:px,y:py+11,'text-anchor':'middle','font-size':9,fill:'var(--mute)'});
    pt2.textContent = `v_${p}`; svg.appendChild(pt2);

    // ℤ_p compact subring indicator
    if(!isSel){
      const zi = SVG('text',{x:px,y:py+22,'text-anchor':'middle','font-size':8,fill:'rgba(179,157,219,0.5)'});
      zi.textContent = `⊃ℤ${p}`; svg.appendChild(zi);
    }

    const hit = SVG('ellipse',{cx:px,cy:py,rx:34,ry:19,fill:'transparent',style:'cursor:pointer'});
    hit.addEventListener('click',()=>{
      selected = selected===p?null:p;
      draw(selected);
      out.textContent = selected ? descriptions[selected] : 'Click a node to see details.';
    });
    svg.appendChild(hit);
  });

  // label: restricted product condition
  const lbl = SVG('text',{x:centerX,y:H-10,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  lbl.textContent = 'Admissibility: x_p ∈ ℤ_p for all but finitely many p';
  svg.appendChild(lbl);
}

draw(null);

