const r2=$('#crt-r2'), r3=$('#crt-r3'), r5=$('#crt-r5');
const goBtn=$('#crt-go'), svg=$('#crt-svg'), out=$('#crt-out');

function solve(){
  const a2=parseInt(r2.value), a3=parseInt(r3.value), a5=parseInt(r5.value);
  // brute force mod 30
  let sol = -1;
  for(let n=0;n<30;n++){
    if(n%2===a2 && n%3===a3 && n%5===a5){ sol=n; break; }
  }

  svg.innerHTML='';
  const W=620, H=180, rowH=50, startY=30, labelW=60;
  const mods=[2,3,5], residues=[a2,a3,a5], cols=['var(--blue)','var(--yellow)','var(--pink)'];

  mods.forEach((m,i)=>{
    const y=startY+i*rowH;
    const cellW = (W-labelW-20)/m;
    // label
    const lbl=SVG('text',{x:10,y:y+16,'font-size':13,fill:cols[i]});
    lbl.textContent=`mod ${m}:`; svg.appendChild(lbl);
    for(let k=0;k<m;k++){
      const x=labelW+k*cellW;
      const isRes=k===residues[i];
      svg.appendChild(SVG('rect',{x:x+2,y:y,width:cellW-4,height:30,rx:4,
        fill:isRes?cols[i]:'var(--panel2)',stroke:cols[i],'stroke-width':1,opacity:isRes?0.9:0.4}));
